import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        Arrays.sort(nums);
        long maxLen = 1;
        for (int i = 0; i < n; i++) {
            long target = nums[i] * k;
            int low = i;
            int high = n - 1;
            int result = i - 1;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (nums[mid] <= target) {
                    result = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            if (result >= i) {
                long currentLen = result - i + 1;
                if (currentLen > maxLen) {
                    maxLen = currentLen;
                }
            }
        }
        return n - maxLen;
    }
}
